import { useSlider } from '../hooks';
import { SLIDER_IMAGES, C } from '../config/constants';

export default function Slider() {
  const { current, goNext, goPrev } = useSlider(SLIDER_IMAGES.length);

  const s = {
    wrap: {
      position: 'relative', maxWidth: '400px', margin: '1.5rem auto 0',
      overflow: 'hidden', borderRadius: '12px',
      boxShadow: '0 8px 24px rgba(0,0,0,0.15)',
    },
    track: {
      transform: `translateX(-${current * 100}%)`,
    },
    btn: (side) => ({
      position: 'absolute', top: '50%',
      [side]: '10px',
      transform: 'translateY(-50%)',
      border: 'none', borderRadius: '8px',
      background: 'rgba(0,51,102,0.8)',
      backdropFilter: 'blur(4px)',
      color: C.groc, fontSize: '2rem',
      padding: '0.4rem 0.75rem',
      cursor: 'pointer', zIndex: 10,
    }),
  };

  return (
    <div style={s.wrap} className="slider-wrap">
      <div className="slider-track" style={s.track}>
        {SLIDER_IMAGES.map((img, i) => (
          <img key={i} src={`assets/que-fem/${img}`} alt={`Foto ${i + 1}`} />
        ))}
      </div>
      <button className="slider-btn" style={s.btn('left')}  onClick={goPrev} aria-label="Anterior">❮</button>
      <button className="slider-btn" style={s.btn('right')} onClick={goNext} aria-label="Següent">❯</button>
    </div>
  );
}
